// Récupérer le texte extrait du PDF et les données du formulaire
const cvText = $input.first().json.text || $input.first().json.content || '';
const form = $('Formulaire CV').first().json;

return [{
  json: {
    cv_text: cvText,
    desired_title: form['Poste recherché'] || '',
    location: form['Lieu'] || '',
    country_raw: form['Pays'] || 'us'
  }
}];

const raw = $input.first().json.text || $input.first().json.response || '';
const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
let profile;
try {
  profile = JSON.parse(cleaned);
} catch {
  profile = { search_keywords: 'développeur', primary_job_title: 'développeur' };
}

// Extraire le code pays depuis la sélection du formulaire (ex: "France (fr)" → "fr")
const prep = $('Préparer données').first().json;
const countryMatch = (prep.country_raw || 'us').match(/\(([a-z]{2})\)/);
const country = countryMatch ? countryMatch[1] : 'us';

return [{
  json: {
    ...profile,
    desired_title: prep.desired_title || profile.primary_job_title,
    location: prep.location || '',
    country,
    cv_text: prep.cv_text
  }
}];

// Fusionner les détails de l'offre avec le profil candidat
const job = $input.first().json;
const profile = $('Parser profil JSON').first().json;
const searchResult = $('Recherche Indeed').item.json;

return [{
  json: {
    // Données offre
    job_id: job.jobKey || searchResult.job_id,
    job_title: job.title || searchResult.title,
    company: job.company || searchResult.company,
    location: job.location || searchResult.location,
    description: (job.jobDescription || job.description || searchResult.snippet || '').substring(0, 2000),
    apply_url: job.viewJobLink || searchResult.link,
    salary: job.salarySnippet || '',
    // Profil candidat
    candidate_name: profile.name,
    candidate_skills: profile.skills,
    candidate_experience: profile.years_experience,
    cv_text: profile.cv_text
  }
}];

